import os, re
patterns = {
 'AWS_ACCESS_KEY_ID': re.compile(r'AKIA[0-9A-Z]{16}'),
 'AWS_SECRET': re.compile(r'(?i)aws_secret_access_key'),
 'AWS_ACCESS_kw': re.compile(r'(?i)aws_access_key_id'),
 'HF': re.compile(r'hf_[A-Za-z0-9]{30,}'),
 'GHP': re.compile(r'ghp_[A-Za-z0-9]{30,}'),
 'GH_PAT': re.compile(r'github_pat_[A-Za-z0-9_]{40,}'),
 'GHO': re.compile(r'gho_[A-Za-z0-9]{30,}'),
 'SECRET_WORD': re.compile(r'(?i)(secret|api[_-]?key|token|password)'),
 'B64_40': re.compile(r'[A-Za-z0-9/+]{40}'),
}
for root, dirs, files in os.walk('.'):
    dirs[:] = [d for d in dirs if d not in ('.git', '.lemoncrow')]
    for f in files:
        p = os.path.join(root, f)
        try:
            data = open(p, encoding='utf-8', errors='replace').read()
        except Exception:
            continue
        for i, line in enumerate(data.splitlines(), 1):
            for name, pat in patterns.items():
                if name in ('SECRET_WORD','B64_40'):
                    continue
                if pat.search(line):
                    print(f"{p}:{i}:{name}: {line.strip()[:200]}")
EOF
python3 /tmp/scan.py

