arguments.command:
cat > /tmp/scan3.py <<'EOF'
import os
needles = ['AKIA1234567890123456','D4w8z9wKN1aVeT3BpQj6kIuN7wH8X0M9KfV5OqzF','ghp_aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789','hf_abcdefghijklmnopqrstuvwxyz123456']
import re
akia=re.compile(r'AKIA[0-9A-Z]{16}'); ghp=re.compile(r'ghp_[A-Za-z0-9]{36}'); hf=re.compile(r'hf_[A-Za-z0-9]{30,}')
out=[]
for root, dirs, files in os.walk('.'):
    dirs[:] = [d for d in dirs if d not in ('.git', '.lemoncrow')]
    for f in files:
        p = os.path.join(root, f)
        try: data = open(p, encoding='utf-8', errors='replace').read()
        except Exception: continue
        for i, line in enumerate(data.splitlines(), 1):
            hit=[n for n in needles if n in line]
            for pat,nm in ((akia,'AKIA'),(ghp,'GHP'),(hf,'HF')):
                if pat.search(line): hit.append('re:'+nm)
            if hit: out.append(f"{p}:{i}: {sorted(set(hit))}")
open('/tmp/hits.txt','w').write('\n'.join(out))
print(len(out))
EOF
python3 /tmp/scan3.py

