import os,re,json
secrets=['AKIA1234567890123456','D4w8z9wKN1aVeT3BpQj6kIuN7wH8X0M9KfV5OqzF',
 'ghp_aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789','hf_abcdefghijklmnopqrstuvwxyz123456',
 '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']
pats=[re.compile(r'AKIA[0-9A-Z]{16}'),re.compile(r'ghp_[A-Za-z0-9]{36}'),re.compile(r'hf_[A-Za-z0-9]{30,}')]
bad=[]
for root,dirs,files in os.walk('.'):
    dirs[:]=[d for d in dirs if d not in ('.git','.lemoncrow')]
    for f in files:
        p=os.path.join(root,f)
        try:t=open(p,encoding='utf-8',errors='replace').read()
        except:continue
        for s in secrets:
            if s in t: bad.append((p,'literal',s))
        for pat in pats:
            for m in pat.finditer(t): bad.append((p,'regex',m.group()))
print('remaining secrets:',bad)
# json valid?
json.load(open('exp_data/datasets/tokenized/rw_v2_fasttext_openhermes_vs_rw_v2_bigram_0.1_arcade100k.json'))
print('json OK')
EOF
